const NL = String.fromCharCode(10);
export const OFFICIAL_V88 = (() => {
  const m = new Map();
  for (const l of RAW.split(NL)) {
    if (!l) continue;
    const [s, dc, drc, dbc, w, d, h] = l.split('|');
    m.set(s, { dc: +dc || 0, drc: +drc || 0, dbc: +dbc || 0, w: +w || null, d: +d || null, h: +h || null });
  }
  return m;
})();

export function findOfficial(sku) {
  return OFFICIAL_V88.get(sku) || OFFICIAL_V88.get(String(sku || '').replace(/^FC-/, '')) || null;
}
export const OFFICIAL_SKU_COUNT = OFFICIAL_V88.size;

