const norm = (s) => String(s || '').trim().toUpperCase();
// Door rows carry _B/_W suffixes (base/wall variants); check both.
const doorKeys = (door) => [norm(door) + '_B', norm(door) + '_W', norm(door)];

export function checkStyleCompat({ door, species, finish, drawerFront }) {
  const issues = [];
  const D = doorKeys(door), sp = norm(species), fin = norm(finish), df = norm(drawerFront);
  const dsKnown = [...DOOR_X_SPECIES].some(p => D.some(d => p.startsWith(d + '::')));
  if (dsKnown && species && !D.some(d => DOOR_X_SPECIES.has(d + '::' + sp)))
    issues.push(`Door ${door} is not offered in ${species}`);
  const dfKnown = [...DOOR_X_FINISH].some(p => D.some(d => p.startsWith(d + '::')));
  if (dfKnown && finish && fin !== 'NATURAL' && !D.some(d => DOOR_X_FINISH.has(d + '::' + fin)))
    issues.push(`Door ${door} is not offered in finish ${finish}`);
  const sfKnown = [...SPECIES_X_FINISH].some(p => p.startsWith(sp + '::'));
  if (sfKnown && finish && fin !== 'NATURAL' && !SPECIES_X_FINISH.has(sp + '::' + fin))
    issues.push(`${species} is not offered in finish ${finish}`);
  const ddfKnown = [...DOOR_X_DF].some(p => D.some(d => p.startsWith(d + '::')));
  if (ddfKnown && drawerFront && !D.some(d => DOOR_X_DF.has(d + '::' + df)))
    issues.push(`Drawer front ${drawerFront} does not pair with door ${door}`);
  return issues;
}
